import Fixtures from '../../components/data/fixtures'


const ResultsGrid = () => {
    return(

        <>
        <div>Hi</div>
        {Fixtures.map(f => (
            <tr key={f.id}>
            <td>{f.address}</td>
            <td>{f.country}</td>
            <td>{f.price}</td>
        </tr>
        ))}
        </>
    );
}
export default ResultsGrid;
